  1→import { useEffect, useState } from 'react';
  2→import { getBookmarks } from '../../../API/Api';
  3→import { useAuth } from '../../Context/useAuth';
  4→import './bookmarks.css';
  5→import { useInfiniteQuery, useQueryClient } from '@tanstack/react-query';
  6→import ParseContent from '../HomePage/postCards/parseData';
  7→import CalculateText from '../HomePage/postCards/calculateReadingTime';
  8→import { MoonLoader } from 'react-spinners';
  9→import { motion, AnimatePresence } from 'framer-motion';
 10→import { handleCLickContent, handleClickProfile } from '../../../helpers/handleClicks';
 11→import { useNavigate } from 'react-router-dom';
 12→import { useInView } from 'react-intersection-observer';
 13→import { useRef } from 'react';
 14→import VerifiedBadge from '../Badge/VerifiedBadge';
 15→import formatPostDate from '../../../helpers/formatDateString';
 16→import { handleImageFallback } from '../../utils/handleImageFallback';
 17→
 18→const Bookmarks = () =>{
 19→    const {user, session} = useAuth();
 20→    const userId = user?.userData?.[0].id
 21→    const navigate = useNavigate();
 22→
 23→    const {ref: inviewRef, inView} = useInView({
 24→        threshold: 0.2
 25→    });
 26→    const timeOutRef = useRef();
 27→    const scrollToTop = useRef();
 28→    const modalRef = useRef(null);
 29→
 30→    const [bookmarkIdSettings, setBookmarkIdSettings] = useState('');
 31→    const [showHeaders, setShowHeaders] = useState(true);
 32→
 33→    const handleclickUserProfile = handleClickProfile(navigate);
 34→
 35→    const handleClickBookmarkSettings = (e, journalId) => {
 36→        e.stopPropagation();
 37→        setBookmarkIdSettings(journalId === bookmarkIdSettings ? null : journalId)
 38→    }
 39→
 40→    const handleBackLocation = (e) =>{
 41→        e.stopPropagation();
 42→        window.history.back();
 43→    }
 44→
 45→    const handleClick = handleCLickContent(navigate);
 46→
 47→    const queryClient = useQueryClient();
 48→    const {data, isLoading, isFetchingNextPage, hasNextPage, fetchNextPage} = useInfiniteQuery({
 49→        queryKey: ['getBookmarks', userId],
 50→        queryFn: ({queryKey, pageParam = null}) => getBookmarks(pageParam, 5, queryKey[1], session?.access_token),
 51→        getNextPageParam: (lastPage) => {
 52→            if(lastPage?.hasMore){
 53→                const lastBookmark = lastPage.bookmarks[lastPage?.bookmarks?.length - 1];
 54→                return new Date(lastBookmark.created_at).toISOString();
 55→            } else {
 56→                return undefined;
 57→            }
 58→        },
 59→        enabled: !!userId,
 60→        refetchOnWindowFocus: false,
 61→        staleTime: 1000 * 60 * 5,
 62→    })
 63→
 64→    useEffect(() =>{
 65→        if(inView && hasNextPage && !isFetchingNextPage){
 66→            fetchNextPage();
 67→        }
 68→
 69→    }, [hasNextPage, fetchNextPage, isFetchingNextPage, inView])
 70→
 71→    useEffect(() =>{
 72→        const scroll = () =>{
 73→            setShowHeaders(false)
 74→            if(timeOutRef.current){
 75→                clearTimeout(timeOutRef.current)
 76→            }
 77→            timeOutRef.current = setTimeout(() =>{
 78→                setShowHeaders(true)
 79→            }, 500)
 80→        }
 81→
 82→        document.addEventListener('scroll', scroll, true)
 83→        return () =>{
 84→             if(timeOutRef.current){
 85→                clearTimeout(timeOutRef.current);
 86→            }
 87→            document.removeEventListener('scroll', scroll, true)
 88→        }
 89→    }, [])
 90→
 91→    useEffect(() =>{
 92→        console.log(data)
 93→    }, [data])
 94→
 95→    useEffect(() => {
 96→        const handleClickOutside = (e) =>{
 97→            if(modalRef.current && !modalRef.current.contains(e.target)){
 98→                setBookmarkIdSettings(null)
 99→            }
100→        }
101→        window.addEventListener('click', handleClickOutside)
102→        return() => {
103→            window.removeEventListener('click', handleClickOutside)
104→        }
105→    }, [])
106→
107→    const journals = data?.pages?.flatMap((journal) => journal.bookmarks|| []);
108→    const totalBookmarks = data?.pages?.flatMap((journal) => journal.totalBookmarks)
109→
110→    useEffect(() => {
111→        if(!isLoading && scrollToTop.current){
112→            scrollToTop.current.scrollIntoView({behavior: 'smooth'});
113→        }
114→    }, [isLoading])
115→
116→    if(isLoading){
117→        return(
118→            <div className='bookmark-loading-container'>
119→                <MoonLoader loading={isLoading} color="var(--loader-color)" speedMultiplier={1} size={20}/>
120→            </div>
121→        )
122→    }
123→    if(journals?.length === 0){
124→        return(
125→            <div className='bookmark-parent-container'>
126→                <p>No bookmarks available</p>
127→            </div>
128→        )
129→    }
130→
131→
132→    return(
133→        <>
134→        <div ref={scrollToTop}/>
135→        <AnimatePresence>
136→        {showHeaders && (
137→            <motion.div
138→            className='bookmarks-header'
139→            initial={{opacity: 0}}
140→            animate={{opacity: 1, transition:{ type: 'spring', stiffness: 300, damping: 25, mass: 0.8}}}
141→            exit={{opacity:0, y: -20, transition:{duration: 0.2, ease: 'easeInOut'}}}
142→            >
143→                <div onClick={(e) => handleBackLocation(e)} className='back-button'>
144→                    <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M360-240 120-480l240-240 56 56-144 144h568v80H272l144 144-56 56Z"/></svg>
145→                </div>
146→
147→                <p className='bookmarks-header-text'>Bookmarks <span className='bookmarks-header-count'>({totalBookmarks})</span></p>
148→            </motion.div>
149→        )}
150→        </AnimatePresence>
151→
152→        <div className='bookmark-parent-container'>
153→            {journals?.map((journal, index) => {
154→                const parsedContent = ParseContent(journal.journals.content);
155→                return(
156→                    <motion.div
157→                        className='bookmark-card'
158→                        key={journal.journals.id || index}
159→                    >
160→
161→                        {parsedContent.firstImage && (
162→                            <img
163→                                className="bookmark-card-image-banner"
164→                                src={parsedContent.firstImage.src}
165→                                alt={journal?.journals?.title ? `${journal.journals.title} cover image` : "Bookmarked post cover image"}
166→                                loading="lazy"
167→                                onError={handleImageFallback}
168→                                onClick={(e) => handleClick(
169→                                    e,
170→                                    journal.journals.content,
171→                                    parsedContent.wholeText,
172→                                    journal.journals.title,
173→                                    journal.journals.user_id,
174→                                    journal.journals.users.name,
175→                                    journal.journals.users.image_url,
176→                                    journal.journals.created_at,
177→                                    journal.journals.id,
178→                                    journal.has_liked,
179→                                    journal.journals.comment_count[0]?.count,
180→                                    journal.has_bookmarked,
181→                                    journal.journals.like_count?.[0]?.count,
182→                                    journal.journals.bookmark_count?.[0]?.count,
183→                                    journal.journals.users.badge
184→                                )}
185→                            />
186→                        )}
187→
188→                        <div className="card-content">
189→                            <div onClick={(e) => handleClick(
190→                                e,
191→                                journal.journals.content,
192→                                parsedContent.wholeText,
193→                                journal.journals.title,
194→                                journal.journals.user_id,
195→                                journal.journals.users.name,
196→                                journal.journals.users.image_url,
197→                                journal.journals.created_at,
198→                                journal.journals.id,
199→                                journal.has_liked,
200→                                journal.journals.comment_count[0]?.count,
201→                                journal.has_bookmarked,
202→                                journal.journals.like_count?.[0]?.count,
203→                                journal.journals.bookmark_count?.[0]?.count,
204→                                journal.journals.users.badge
205→                            )}
206→                                className="content-container">
207→
208→                                <div className='feed-text-content-container'>
209→                                    <div className='feed-title-content'>
210→                                        <h2 className="feed-title">{journal.journals.title.length > 55 ? `${journal.journals.title.substring(0, 55)}...` : journal.journals.title}</h2>
211→                                    </div>
212→                                    <p className="feed-text-content">{parsedContent.slicedText}</p>
213→                                </div>
214→                            </div>
215→                        </div>
216→
217→                        <div className="bookmark-card-footer">
218→                            <div className='user-info-child-container'>
219→                                <div onClick={(e) => handleclickUserProfile(e, user?.userData?.[0].id, journal.journals.user_id)} className={`user-avatar-container ${journal?.journals?.users?.badge === 'legend' ? 'avatar-ring-legend' : journal?.journals?.users?.badge === 'og' ? 'avatar-ring-og' : ''}`}>
220→                                    <img loading='lazy' src={journal?.journals?.users?.image_url || '/assets/profile.jpg'} className="user-info-avatar" alt={`${journal?.journals?.users?.name || "User"} profile picture`} />
221→                                </div>
222→                                <div onClick={(e) => handleclickUserProfile(e, user?.userData?.[0].id, journal.journals.user_id)} className="user-name-container">
223→                                    <p className="user-newsfeed-name">{journal?.journals?.users?.name}</p>
224→                                    <VerifiedBadge badge={journal?.journals?.users?.badge} size={14} />
225→                                </div>
226→                                <div className="name-info-separator">•</div>
227→                                <p className="user-post-date">{formatPostDate(journal.created_at)}</p>
228→                            </div>
229→
230→                            <div className="bookmark-card-footer-right">
231→                                <div className="reading-time-container">
232→                                    <p className="reading-time-text">{CalculateText(parsedContent.wholeText)}</p>
233→                                </div>
234→
235→                                <div className="user-post-settings">
236→                                    <svg onClick={(e) => handleClickBookmarkSettings(e, journal.journals.id)} xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="M240-400q-33 0-56.5-23.5T160-480q0-33 23.5-56.5T240-560q33 0 56.5 23.5T320-480q0 33-23.5 56.5T240-400Zm240 0q-33 0-56.5-23.5T400-480q0-33 23.5-56.5T480-560q33 0 56.5 23.5T560-480q0 33-23.5 56.5T480-400Zm240 0q-33 0-56.5-23.5T640-480q0-33 23.5-56.5T720-560q33 0 56.5 23.5T800-480q0 33-23.5 56.5T720-400Z"/></svg>
237→                                    {bookmarkIdSettings === journal.journals.id && (
238→                                        <motion.div
239→                                        initial={{opacity:0 ,scale:0}}
240→                                        animate={{opacity:1, scale:1, transition: {type: "tween", duration: 0.3}}}
241→                                        exit={{opacity:0, scale:0, transition: {type: "tween", duration: 0.3}}}
242→                                        ref={modalRef}
243→                                        className="setting-modal"
244→                                        >
245→                                            <p>{journal.journals.title}</p>
246→                                        </motion.div>
247→                                    )}
248→                                </div>
249→                            </div>
250→                        </div>
251→
252→                    </motion.div>
253→                )
254→            })}
255→            <div ref={inviewRef} className='inview-container'>
256→                <MoonLoader loading={isFetchingNextPage} color="rgba(255, 255, 255, 0.64)" speedMultiplier={1} size={20}/>
257→            </div>
258→        </div>
259→        </>
260→    )
261→}
262→export default Bookmarks;
263→

  1→import ParseContent from '../HomePage/postCards/parseData';
  2→import { deleteCollection, getCollections } from '../../../API/Api';
  3→import { useAuth } from '../../Context/useAuth';
  4→import { useInfiniteQuery, useQueryClient } from '@tanstack/react-query';
  5→import { useEffect, useState } from 'react';
  6→import { useInView } from 'react-intersection-observer';
  7→import { FadeLoader, MoonLoader } from 'react-spinners';
  8→import formatPostDate from '../../../helpers/formatDateString';
  9→import { useNavigate } from 'react-router-dom';
 10→import { AnimatePresence, motion } from 'framer-motion';
 11→import { useUpdateCollectionPrivacyMutation } from '../../utils/useMutation';
 12→
 13→const GradientHeaderIcon = () => (
 14→    <svg xmlns="http://www.w3.org/2000/svg" width="48" height="48" viewBox="0 0 24 24" fill="currentColor" style={{ color: '#ffffff' }}>
 15→        <path d="M18,2 C19.3807,2 20.5,3.11929 20.5,4.5 L20.5,18.75 C20.5,19.1642 20.1642,19.5 19.75,19.5 L5.5,19.5 C5.5,20.0523 5.94772,20.5 6.5,20.5 L19.75,20.5 C20.1642,20.5 20.5,20.8358 20.5,21.25 C20.5,21.6642 20.1642,22 19.75,22 L6.5,22 C5.11929,22 4,20.8807 4,19.5 L4,4.5 C4,3.11929 5.11929,2 6.5,2 L18,2 Z"/>
 16→    </svg>
 17→);
 18→
 19→const CollectionCards = () =>{
 20→    const {user, session} = useAuth();
 21→    const {ref, inView} = useInView({threshold: 0.2})
 22→    const queryClient = useQueryClient();
 23→
 24→    const [settingId, setSettingId] = useState('');
 25→    const [isDeleting, setIsDeleting] = useState(false);
 26→    const [isDeleted, setIsDeleted] = useState(false);
 27→    const [confirmDeleteId, setConfirmDeleteId] = useState('');
 28→
 29→    const [showUpdatePrivacyMessageId, setShowUpdatePrivacyMessageId] = useState('');
 30→
 31→    const navigate = useNavigate();
 32→
 33→    const settingsList = [
 34→            {
 35→                icon:
 36→                <svg xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 16 16" fill="none">
 37→                    <g fill="currentColor">
 38→                        <path fillRule="evenodd" d="M5.58 7C5.835 5.124 6.667 3.335 8 1.836a10.074 10.074 0 011.806 2.878.75.75 0 101.388-.568 11.412 11.412 0 00-1.322-2.372A6.503 6.503 0 0114.5 8 .75.75 0 0016 8a8 8 0 10-11.31 7.285.75.75 0 10.622-1.365A6.504 6.504 0 011.519 8.5h2.503c.04.563.122 1.12.248 1.668a.75.75 0 101.462-.336c-.1-.438-.17-.883-.205-1.332H7A.75.75 0 007 7H5.58zM4.07 7H1.576a6.508 6.508 0 014.552-5.226A11.095 11.095 0 004.068 7z" clipRule="evenodd"/>
 39→                        <path d="M11.75 12.25a.75.75 0 00-1.5 0v.5a.75.75 0 001.5 0v-.5z"/>
 40→                        <path fillRule="evenodd" d="M8.518 9.012c.035-.627.13-1.235.366-1.738.174-.37.435-.704.816-.94C10.08 6.101 10.52 6 11 6c.48 0 .921.1 1.3.334.381.236.642.57.816.94.236.503.331 1.111.366 1.738A2.25 2.25 0 0115.5 11.25v2.5A2.25 2.25 0 0113.25 16h-4.5a2.25 2.25 0 01-2.25-2.25v-2.5a2.25 2.25 0 012.018-2.238zM10.022 9c.032-.481.102-.838.22-1.087a.662.662 0 01.245-.302c.09-.055.243-.111.513-.111s.423.056.513.111c.087.054.17.141.246.302.117.249.187.606.219 1.087h-1.956zm3.228 1.5a.75.75 0 01.75.75v2.5a.75.75 0 01-.75.75h-4.5a.75.75 0 01-.75-.75v-2.5a.75.75 0 01.75-.75h4.5z" clipRule="evenodd"/>
 41→                    </g>
 42→                </svg>,
 43→                actionOnlyMe: (e, userId, collectionId, isPublic) => {togglePrivacy(e, userId, collectionId, isPublic)},
 44→                label: 'Only me',
 45→            },
 46→            {
 47→                icon:
 48→                <svg xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 16 16" fill="none"><path fill="currentColor" fillRule="evenodd" d="M8 0a8 8 0 100 16A8 8 0 008 0zM6.128 1.774A6.508 6.508 0 001.576 7H4.07a11.095 11.095 0 012.06-5.226zm3.744 0A11.096 11.096 0 0111.932 7h2.492a6.508 6.508 0 00-4.552-5.226zM10.42 7C10.165 5.124 9.333 3.335 8 1.836 6.667 3.335 5.835 5.124 5.58 7h4.84zM5.527 8.5h4.946C10.31 10.557 9.451 12.533 8 14.164 6.55 12.533 5.691 10.557 5.527 8.5zm-1.505 0H1.52a6.505 6.505 0 004.61 5.726C4.896 12.525 4.163 10.555 4.021 8.5zm5.85 5.726c1.231-1.701 1.964-3.671 2.106-5.726h2.503a6.505 6.505 0 01-4.61 5.726z" clipRule="evenodd"/></svg>,
 49→                actionPublic: (e, userId, collectionId, isPublic) => {togglePrivacy(e, userId, collectionId, isPublic)},
 50→                label: 'Public',
 51→            },
 52→            {
 53→                icon:
 54→                <svg xmlns="http://www.w3.org/2000/svg" width="20px" height="20px" viewBox="0 0 24 24" fill="none">
 55→                    <path d="M10 12V17" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
 56→                    <path d="M14 12V17" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
 57→                    <path d="M4 7H20" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
 58→                    <path d="M6 10V18C6 19.6569 7.34315 21 9 21H15C16.6569 21 18 19.6569 18 18V10" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
 59→                    <path d="M9 5C9 3.89543 9.89543 3 11 3H13C14.1046 3 15 3.89543 15 5V7H9V5Z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
 60→                </svg>,
 61→                actionDelete: (e, collectionId) => {setConfirmDeleteId(collectionId); setSettingId('');},
 62→                label: 'Delete'
 63→
 64→            }
 65→        ]
 66→
 67→    const {
 68→        data,
 69→        isFetchingNextPage,
 70→        hasNextPage,
 71→        fetchNextPage,
 72→        isLoading
 73→    } = useInfiniteQuery({
 74→        queryKey: ['getCollections', user?.userData?.[0].id],
 75→        queryFn: ({pageParam, queryKey}) => getCollections(queryKey[1], pageParam, 5, session?.access_token),
 76→        getNextPageParam: (lastPage) => {
 77→            if(lastPage?.hasMore){
 78→                const lastJournal = lastPage.data[lastPage?.data?.length - 1];
 79→                return new Date(lastJournal?.created_at).toISOString();
 80→            } else{
 81→                return undefined;
 82→            }
 83→        },
 84→        enabled: !!user?.userData?.[0].id,
 85→        refetchOnWindowFocus: false,
 86→        staleTime: 1000 * 60 * 5
 87→    })
 88→
 89→    const handleClickCards = (e, collectionId, collectionName, collectionDescription) =>{
 90→        e.stopPropagation();
 91→        navigate(
 92→            '/home/collectionCards',{
 93→                state: {
 94→                    collectionId: collectionId,
 95→                    collectionName: collectionName,
 96→                    collectionDescription:collectionDescription
 97→                }
 98→            }
 99→        )
100→
101→    }
102→
103→    const mutateCollectionPrivacy = useUpdateCollectionPrivacyMutation(session);
104→
105→    const togglePrivacy = (e, userId, collectionId, isPublic) =>{
106→        e.stopPropagation();
107→
108→        const privacy = isPublic === 'private' ? 'public' : 'private';
109→
110→        const formdata = new FormData();
111→        formdata.append('collectionId', collectionId)
112→        formdata.append('userId', userId)
113→        formdata.append('isPublic', privacy)
114→        mutateCollectionPrivacy.mutate(formdata);
115→
116→        setShowUpdatePrivacyMessageId(collectionId === showUpdatePrivacyMessageId ? '' : collectionId);
117→        let timer;
118→        clearTimeout(timer);
119→        timer = setTimeout(() => {
120→            setShowUpdatePrivacyMessageId('')
121→        }, 2500);
122→    }
123→
124→
125→    const handleClickSettings = (e, collectionId) =>{
126→        e.stopPropagation();
127→        setSettingId(settingId === collectionId ? '' : collectionId);
128→    }
129→
130→    const handleDeleteCollection = async(e, collectionId) =>{
131→        e.stopPropagation();
132→        setConfirmDeleteId('');
133→        try {
134→            let timer;
135→            setIsDeleting(true);
136→            const message = await deleteCollection(session?.access_token, collectionId);
137→            if(message){
138→                console.log(message)
139→            }
140→            queryClient.invalidateQueries(['getCollectionJournals', collectionId, session?.access_token])
141→            clearTimeout(timer);
142→            setIsDeleted(true)
143→            setIsDeleting(false)
144→
145→            timer = setTimeout(() => {
146→                setIsDeleted(false)
147→            }, 2500);
148→
149→        } catch (error) {
150→            queryClient.invalidateQueries(['getCollectionJournals', collectionId, session?.access_token])
151→            setIsDeleting(false)
152→            throw new Error(error)
153→
154→        }
155→    }
156→
157→    useEffect(()=> {
158→        if(!isFetchingNextPage && hasNextPage && inView){
159→            fetchNextPage();
160→        }
161→    }, [hasNextPage, isFetchingNextPage, fetchNextPage, inView])
162→
163→    useEffect(() =>{
164→        const handleClickOutside = (e) =>{
165→            if(settingId !== null && !e.target.closest('.setting-bttn')){
166→                setSettingId('')
167→            }
168→        }
169→
170→        document.addEventListener('click', handleClickOutside);
171→
172→        return() => {
173→            document.removeEventListener('click', handleClickOutside);
174→        }
175→    }, [])
176→
177→    const collections = data?.pages?.flatMap((page) => page.data) || [];
178→
179→    if(isLoading){
180→        return(
181→            <div className='collection-cards-loading-container'>
182→                {[...Array(6)].map((_, i) => (
183→                    <div key={i} className="skeleton-card" />
184→                ))}
185→            </div>
186→
187→        )
188→    }
189→
190→    return(
191→        <>
192→        {isDeleted && (
193→            <AnimatePresence>
194→            <motion.div
195→            className='deleted-message-container'
196→            initial={{opacity: 0, y: 12}}
197→            animate={{opacity: 1, y: 0}}
198→            transition={{type: 'tween', duration: 0.15}}
199→            >
200→                The collection was deleted
201→            </motion.div>
202→            </AnimatePresence>
203→        )}
204→
205→        {showUpdatePrivacyMessageId && (
206→            <div className='update-privacy-message-container'>
207→                {collections.find(c => c.id === showUpdatePrivacyMessageId)?.is_public === 'private' ? 'Collection privacy was updated to private.' : 'Collection privacy was updated to public.'}
208→            </div>
209→        )}
210→
211→        <div className="collection-cards-container">
212→            {isDeleting && (
213→                <div className='deleting-collection-loading-container'>
214→                    <FadeLoader radius={0} loading={isDeleting}/>
215→                </div>
216→            )}
217→
218→            {collections?.map((collection) => {
219→                const accentIndex = collection.id ? collection.id.toString().charCodeAt(0) % 4 : 0;
220→                return(
221→                    <div key={collection?.id} className='collection-cards'>
222→                        {confirmDeleteId === collection.id && (
223→                            <div className='delete-confirm-overlay'>
224→                                <p>Delete this collection?</p>
